const extractData = $input.first().json.data || $input.first().json;
const triggerData = $('New Lease Document').item.json;

const lease = extractData;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Escalation summary
const escalationType = lease.escalationType || 'Fixed';
const escalationPct = lease.escalationPercentage || 0;
const escalationSchedule = lease.escalationSchedule || 'Annual';
const escalationSummary = `${escalationType}: ${escalationPct}% ${escalationSchedule}`;

// Termination summary
const termAllowed = lease.terminationAllowed ? 'Yes' : 'No';
const termNotice = lease.terminationNoticePeriod || 'N/A';
const termFee = lease.terminationFee || 'N/A';

return [{
  json: {
    propertyAddress: lease.propertyAddress || 'N/A',
    propertyName: lease.propertyName || 'N/A',
    landlordName: lease.landlordName || 'Unknown',
    landlordContact: lease.landlordContact || 'N/A',
    tenantName: lease.tenantName || 'Unknown',
    tenantContact: lease.tenantContact || 'N/A',
    commencementDate: lease.commencementDate || 'N/A',
    expirationDate: lease.expirationDate || 'N/A',
    termYears: lease.termYears || 'N/A',
    baseRentAmount: lease.baseRentAmount || 0,
    rentFrequency: lease.rentFrequency || 'monthly',
    rentPerSqFt: lease.rentPerSqFt || 0,
    escalationSummary: escalationSummary,
    securityDeposit: lease.securityDeposit || 0,
    camAmount: lease.camAmount || 0,
    camCap: lease.camCap || 'No cap',
    renewalOptions: lease.renewalOptions || 'None',
    terminationAllowed: termAllowed,
    terminationNotice: termNotice,
    terminationFee: termFee,
    permittedUse: lease.permittedUse || 'N/A',
    parkingSpaces: lease.parkingSpaces || 0,
    parkingCost: lease.parkingCost || 'N/A',
    tiAllowance: lease.tenantImprovementAllowance || 0,
    specialProvisions: lease.specialProvisions || 'None',
    fileName: fileName,
    fileId: fileId,
    processedAt: new Date().toISOString()
  }
}];

